const items = $input.all();
const first = items[0] ? items[0].json : {};

const body = first.body || {};
const rawInput = (body.target || first.target || "").toString().trim();

// Normalize target
let host = rawInput;

try {
  host = new URL(rawInput).hostname;
} catch (e) {
  host = rawInput
    .replace(/^https?:\/\//i, "")
    .replace(/\/.*$/, "");
}

host = host.replace(/^www\./i, "").toLowerCase();

// Detect IP
const isIp = (() => {
const p=host.split(".");
return p.length===4 && p.every(x=>/^\d+$/.test(x) && Number(x)>=0 && Number(x)<=255);
})();

// Root domain
let root = host;

if (!isIp) {
  const parts = host.split(".");
  const multi=["co.uk","org.uk","gov.uk","ac.uk","co.in","org.in","com.au","net.au"];
  const last2=parts.slice(-2).join(".");
  if(parts.length>2){
    if(multi.includes(last2) && parts.length>2){
      root=parts.slice(-3).join(".");
    }else{
      root=last2;
    }
  }
}
// Learning mode - allow all targets
const authorized = true;

return [{
  json: {
    raw: rawInput,
    domain: host,
    target: host,
    rootDomain: root,
    isIp,
    type: isIp ? "ip" : (rawInput.startsWith("http") ? "url" : "domain"),
    authorized,
    authorizedList: ["ALL TARGETS ALLOWED (Learning Mode)"],
    scanId: $execution.id,
    scannedAt: new Date().toISOString()
  }
}];

function safe(name) { try { const it = $(name).all(); if (!it || !it.length) return null; return it[0].json; } catch (e) { return null; } }
function pick(name) { const j = safe(name); if (!j) return { error: 'no data / node did not run' }; if (j.error) return { error: (typeof j.error === 'string') ? j.error : 'request failed' }; return (j.body !== undefined) ? j.body : j; }

const norm = safe('Normalize & Validate Target') || {};
const recon = {
  whois: pick('WHOIS Lookup'),
  dns_a: pick('DNS A Records'),
  dns_mx: pick('DNS MX Records'),
  dns_txt: pick('DNS TXT Records'),
  dns_ns: pick('DNS NS Records'),
  virustotal: pick('VirusTotal Domain Report'),
  shodan: pick('Shodan DNS Domain'),
  censys: pick('Censys Hosts Search'),
  alienvault_otx: pick('AlienVault OTX'),
  urlscan: pick('URLScan Search'),
  securitytrails: pick('SecurityTrails Domain'),
  anyrun: pick('ANY.RUN Analyses'),
};

const log = { level: 'info', event: 'recon_aggregated', target: norm.target, scanId: norm.scanId, at: new Date().toISOString() };
console.log(JSON.stringify(log));

return [{ json: {
  target: norm.target,
  domain: norm.domain,
  rootDomain: norm.rootDomain,
  type: norm.type,
  scanId: norm.scanId,
  scannedAt: norm.scannedAt,
  recon: recon,
} }];

function link(name) { try { const j = $(name).all()[0].json; return j.webViewLink || j.webContentLink || (j.id ? ('https://drive.google.com/file/d/' + j.id + '/view') : 'N/A'); } catch (e) { return 'N/A'; } }

const rep = $('Build Reports').all()[0].json;
const riskScore = Number(rep.riskScore ?? 0);
let severity;
if (riskScore <= 2) severity = 'Low';
else if (riskScore <= 5) severity = 'Medium';
else if (riskScore <= 8) severity = 'High';
else severity = 'Critical';
const colorMap = {
  Low: 3066993,
  Medium: 15844367,
  High: 15105570,
  Critical: 15158332
};

const color = colorMap[severity] || 9807270;

const links = { md: link('Upload MD Report'), html: link('Upload HTML Report'), json: link('Upload JSON Report'), pdf: link('Upload PDF Report') };
const findings = Array.isArray(rep.findings) ? rep.findings : [];
let findingsText = findings.slice(0, 5).map(function (f, i) { return (i + 1) + '. ' + (f.category || f.title || '') + ' [' + (f.severity || '') + ']'; }).join(String.fromCharCode(10));
if (!findingsText) { findingsText = 'No notable findings.'; }
const summary = (rep.executiveSummary || '').toString().slice(0, 1500);

const embed = {
  title: `🛡️ Security Recon Report - ${rep.target || rep.domain}`,
  description:
'✅ Reconnaissance completed successfully.\n\n' +
'🎯 **Target:** ' + (rep.target || 'unknown') + '\n' +
'📊 **Risk Score:** ' + riskScore + '\n' +
'🚨 **Severity:** ' + severity + '\n\n' +
summary,
  color: color,
  timestamp: new Date().toISOString(),
  fields: [
    { name: 'Target', value: (rep.target || 'unknown'), inline: true },
   { name: 'Status', value: '✅ Completed', inline: true },
  { name: '📊 Risk Score', value: String(riskScore), inline: true },
{ name: '🚨 Severity', value: severity, inline: true } ,
    { name: 'Findings (' + findings.length + ')', value: findingsText.slice(0, 1000) },
  {
