  '📝 [Markdown](' + links.md + ')\n' +
  '📦 [JSON](' + links.json + ')'
},
  ],
 footer: {
  text: 'AI Security Recon Agent • Generated Automatically • Educational Use'
},
};

return [{ json: { embed: embed, links: links, target: rep.target, riskScore: riskScore,
severity: severity, findingsCount: findings.length } }];

