const NL = String.fromCharCode(10);
function escapeHtml(s) { return (s === undefined || s === null ? '' : s).toString().replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function badge(text, color){
  return `<span style="
    display:inline-block;
    padding:6px 12px;
    border-radius:20px;
    color:#fff;
    background:${color};
    font-weight:600;
    font-size:13px;
  ">${text}</span>`;
}

function formatDate(date){
  if(!date) return "-";

  const d = new Date(date);

  if(isNaN(d)) return escapeHtml(date);

  return d.toLocaleString("en-GB",{
    day:"2-digit",
    month:"short",
    year:"numeric",
    hour:"2-digit",
    minute:"2-digit"
  });
}
function b64(str) { return Buffer.from(str, 'utf8').toString('base64'); }

